async function createInstantMeeting() {
  try {
    const now = new Date();
    const end = new Date(now.getTime() + 60 * 60000);
    const data = await api('/api/meetings/create', {
      method: 'POST',
      body: JSON.stringify({
        title: 'Instant Meeting',
        meetingType: 'meeting',
        scheduledStart: now.toISOString(),
        scheduledEnd: end.toISOString(),
        openToCompany: true,
      }),
    });
    const id = (data.data || data)._id;
    if (!id) throw new Error('No meeting ID returned');
    window.location.href = `/lecturer-meeting?meeting=${encodeURIComponent(id)}`;
  } catch (e) {
    toastError(e.message || 'Could not create meeting');
  }
}

// ── Meetings auto-poll ────────────────────────────────────────────────────────
let _meetingsPollTimer = null;
let _meetingsKnownLiveIds = new Set();
let _meetingsCountdownTimer = null;

function _stopMeetingsPoll() {
  if (_meetingsPollTimer) { clearInterval(_meetingsPollTimer); _meetingsPollTimer = null; }
  if (_meetingsCountdownTimer) { clearInterval(_meetingsCountdownTimer); _meetingsCountdownTimer = null; }
  _meetingsKnownLiveIds = new Set();
}

function _startCountdownTicker() {
  if (_meetingsCountdownTimer) clearInterval(_meetingsCountdownTimer);
  function tick() {
    const now = Date.now();
    document.querySelectorAll('[data-countdown-ms]').forEach(el => {
      const start = parseInt(el.dataset.countdownMs, 10);
      const diff  = start - now;
      if (diff <= 0) {
        el.textContent = '▶ Start';
        el.disabled = false;
        el.style.background = '#3b82f6';
        el.style.cursor = 'pointer';
        el.style.fontWeight = '700';
        return;
      }
      const totalMins = Math.ceil(diff / 60000);
      if (totalMins < 60) {
        el.textContent = `⏳ In ${totalMins}m`;
      } else {
        const h = Math.floor(totalMins / 60), m = totalMins % 60;
        el.textContent = m ? `⏳ In ${h}h ${m}m` : `⏳ In ${h}h`;
      }
    });
  }
  tick();
  _meetingsCountdownTimer = setInterval(tick, 10000);
}

function _startMeetingsPoll() {
  _stopMeetingsPoll();
  _meetingsPollTimer = setInterval(() => {
    if (document.getElementById('main-content') && currentView === 'meetings') {
      _meetingsSilentRefresh();
    } else {
      _stopMeetingsPoll();
    }
  }, 30000);
}

async function _meetingsSilentRefresh() {
  try {
    const data = await api('/api/meetings');
    offlineCache('meetings', data);
    const meetings = data.data || data.meetings || [];

    // Detect newly-live meetings and toast
    meetings.forEach(m => {
      if (m.status === 'live' && !_meetingsKnownLiveIds.has(String(m._id))) {
        if (_meetingsKnownLiveIds.size > 0) { // skip first load
          const role = currentUser?.role || '';
          const isHost = ['lecturer','manager','admin','superadmin','hod'].includes(role);
          const msg = isHost
            ? `"${m.title}" is live — tap Rejoin`
            : `"${m.title}" is now live — tap Join`;
          toastSuccess(msg);
        }
        _meetingsKnownLiveIds.add(String(m._id));
      }
    });
    // Prune ended meetings from known-live set
    const liveNow = new Set(meetings.filter(m => m.status === 'live').map(m => String(m._id)));
    _meetingsKnownLiveIds.forEach(id => { if (!liveNow.has(id)) _meetingsKnownLiveIds.delete(id); });

    _renderMeetingsData(data);
    _startCountdownTicker();
  } catch(_) { /* silent — don't disrupt UI on background poll error */ }
}

async function renderMeetings() {
  const content = document.getElementById('main-content');
  if (!content) return;
  content.innerHTML = '<div style="padding:32px;text-align:center;color:var(--text-muted);">Loading meetings…</div>';
  if (!isOnline()) {
    const _c = offlineRead('meetings');
    if (_c) { /* render below */ Object.assign(arguments, [_c]); }
    else { content.innerHTML = `<div style="text-align:center;padding:60px 20px"><div style="font-size:48px;margin-bottom:12px">📡</div><div style="font-size:18px;font-weight:700">You're Offline</div><p style="color:var(--text-muted);margin-top:8px">Connect once while online to cache this page.</p></div>`; return; }
  }
  const _meetingsCached = !isOnline() ? offlineRead('meetings') : null;
  let data;
  if (_meetingsCached) { data = _meetingsCached; }
  else {
    try { data = await api('/api/meetings'); offlineCache('meetings', data); }
    catch(e) {
      const _c = offlineRead('meetings');
      if (_c) { data = _c; }
      else { content.innerHTML = `<div class="card"><p style="color:#ef4444;">${e.message}</p></div>`; return; }
    }
  }
  // Seed known-live set on first render (no toast on initial load)
  const meetings0 = data.data || data.meetings || [];
  meetings0.forEach(m => { if (m.status === 'live') _meetingsKnownLiveIds.add(String(m._id)); });
  _renderMeetingsData(data);
  _startMeetingsPoll();
  _startCountdownTicker();
}

function _renderMeetingsData(data) {
  const content = document.getElementById('main-content');
  if (!content) return;
  try {
    const canCreate = ['manager', 'lecturer'].includes(currentUser.role);
    const canManageExisting = ['manager', 'lecturer', 'admin', 'superadmin', 'hod'].includes(currentUser.role);

    const devLock = currentUser?.accountDeviceLock;
    const isDeviceLocked = devLock?.isLocked && devLock?.lockedUntil && new Date(devLock.lockedUntil) > new Date();

    function fmtDate(dt) {
      if (!dt) return '—';
      const d = new Date(dt);
      return d.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' })
           + ' · ' + d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
    }

    function fmtDuration(start, end) {
      if (!start || !end) return '—';
      const min = Math.round((new Date(end) - new Date(start)) / 60000);
      if (min < 60) return `${min}m`;
      const h = Math.floor(min / 60), m = min % 60;
      return m ? `${h}h ${m}m` : `${h}h`;
    }

    const MEETING_TYPE_LABELS = {
      meeting: 'Meeting', lecture: 'Lecture', proctored_quiz: 'Proctored Quiz',
      snap_quiz: 'Snap Quiz', oral_exam: 'Oral Exam',
      staff_conference: 'Staff Conference', live_assessment: 'Live Assessment',
    };
    const MEETING_TYPE_ICONS = {
      lecture: '🎓', meeting: '🎥', proctored_quiz: '📝',
      snap_quiz: '⚡', oral_exam: '🗣️', staff_conference: '👔', live_assessment: '📋',
    };

    function meetingCard(m) {
      const isLive      = m.status === 'live';
      const isScheduled = m.status === 'scheduled';
      const isEnded     = ['ended', 'completed', 'cancelled'].includes(m.status);
      // Support both old (createdBy) and new (creatorId) field shapes
      const hostId   = m.creatorId?._id || m.creatorId || m.createdBy?._id;
      const hostName = m.creatorId?.name || m.createdBy?.name || 'Unknown';
      const isCreator   = String(hostId) === String(currentUser._id);
      const isAdmin     = ['admin', 'superadmin', 'hod'].includes(currentUser.role);
      const isInvigil   = (m.invigilators || []).some(i => String(i._id || i) === String(currentUser._id));
      const canControl  = canManageExisting && (isCreator || isAdmin || isInvigil);
      const durationMin = m.scheduledStart && m.scheduledEnd
        ? Math.round((new Date(m.scheduledEnd) - new Date(m.scheduledStart)) / 60000)
        : (m.duration || '—');

      const borderColor = isLive ? '#22c55e' : isScheduled ? '#3b82f6' : '#e5e7eb';
      const statusBadgeStyle = isLive ? 'background:#dcfce7;color:#15803d;' : isScheduled ? 'background:#dbeafe;color:#1d4ed8;' : m.status==='cancelled' ? 'background:#fee2e2;color:#b91c1c;' : 'background:#f3f4f6;color:#6b7280;';
      const statusText = isLive ? '● LIVE' : isScheduled ? 'Scheduled' : m.status === 'cancelled' ? 'Cancelled' : 'Ended';
      const typeLabel  = MEETING_TYPE_LABELS[m.meetingType] || '';
      const safeName   = (m.title || '').replace(/'/g, "\\'");
      const pCount     = (isLive && m.participantCount != null) ? m.participantCount : null;
      const pBadge     = pCount !== null
        ? `<span style="display:inline-flex;align-items:center;gap:4px;background:#f0fdf4;border:1px solid #bbf7d0;color:#15803d;font-size:11px;font-weight:700;padding:2px 8px;border-radius:20px;margin-left:6px;">
            <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
            ${pCount}
          </span>`
        : '';

      return `<div style="background:#fff;border-radius:14px;box-shadow:0 1px 6px rgba(0,0,0,0.07);padding:16px;border:1px solid #f1f5f9;border-left:4px solid ${borderColor};margin-bottom:0;">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:10px;">
          <div style="flex:1;min-width:0;">
            <div style="font-weight:700;font-size:15px;color:#0f172a;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${esc(m.title)}</div>
            ${typeLabel ? `<div style="font-size:10px;font-weight:700;color:#7c3aed;margin-top:2px;text-transform:uppercase;letter-spacing:.5px;">${typeLabel}</div>` : ''}
          </div>
          <div style="display:flex;align-items:center;flex-shrink:0;gap:0;">
            <span style="${statusBadgeStyle}padding:3px 10px;border-radius:20px;font-size:11px;font-weight:700;">${statusText}</span>
            ${pBadge}
          </div>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:12px;font-size:12px;color:#64748b;">
          <div><div style="font-weight:600;color:#0f172a;">Host</div>${esc(hostName)}</div>
          <div><div style="font-weight:600;color:#0f172a;">Duration</div>${durationMin} min</div>
          <div style="grid-column:1/-1;"><div style="font-weight:600;color:#0f172a;">Start</div>${fmtDate(m.scheduledStart)}</div>
        </div>
        <div style="display:flex;gap:6px;flex-wrap:wrap;">
          ${isLive && !canControl && !isDeviceLocked ? `<button style="flex:1;background:#22c55e;color:#fff;border:none;padding:10px 14px;border-radius:9px;font-weight:700;cursor:pointer;font-size:14px;min-width:90px;" onclick="joinMeeting('${m._id}')">▶ Join</button>` : ''}
          ${isLive && canControl ? `<button style="flex:1;background:#22c55e;color:#fff;border:none;padding:10px 14px;border-radius:9px;font-weight:700;cursor:pointer;font-size:14px;min-width:90px;" onclick="startMeeting('${m._id}')">▶ Rejoin</button>` : ''}
          ${isLive && isDeviceLocked ? `<span style="background:#fef3c7;color:#92400e;padding:8px 12px;border-radius:9px;font-size:12px;font-weight:600;">🔒 Locked</span>` : ''}
          ${isScheduled && !canControl ? `<span style="background:#eff6ff;color:#1d4ed8;padding:8px 12px;border-radius:9px;font-size:12px;font-weight:600;">Not Live Yet</span>` : ''}
          ${canControl && isScheduled ? (() => {
            const now = Date.now();
            const start = m.scheduledStart ? new Date(m.scheduledStart).getTime() : 0;
            const minsUntil = Math.ceil((start - now) / 60000);
            const canStart = now >= start - 60000; // allow 1 min early
            return canStart
              ? `<button style="flex:1;background:#3b82f6;color:#fff;border:none;padding:10px 14px;border-radius:9px;font-weight:700;cursor:pointer;font-size:14px;min-width:90px;" onclick="startMeeting('${m._id}')">▶ Start</button>`
              : `<button disabled data-countdown-ms="${start}" onclick="startMeeting('${m._id}')" style="flex:1;background:#93c5fd;color:#fff;border:none;padding:10px 14px;border-radius:9px;font-weight:600;font-size:13px;min-width:90px;cursor:not-allowed;" title="Meeting hasn't reached its scheduled time">⏳ In ${minsUntil}m</button>`;
          })() : ''}
          ${canControl && isLive ? `<button style="background:#0ea5e9;color:#fff;border:none;padding:10px 14px;border-radius:9px;font-weight:700;cursor:pointer;" onclick="openMeetingMonitor('${m._id}')">👁 Monitor</button>` : ''}
          ${canControl && isLive ? `<button style="background:#ef4444;color:#fff;border:none;padding:10px 14px;border-radius:9px;font-weight:700;cursor:pointer;" onclick="endMeeting('${m._id}')">■ End</button>` : ''}
          ${canControl && (isScheduled || isLive) ? `<button style="background:#f1f5f9;color:#374151;border:none;padding:10px 14px;border-radius:9px;font-weight:600;cursor:pointer;" onclick="cancelMeeting('${m._id}')">Cancel</button>` : ''}
          <button style="background:#f1f5f9;color:#374151;border:none;padding:10px 14px;border-radius:9px;font-weight:600;cursor:pointer;" onclick="viewMeetingDetail('${m._id}')">Details</button>
          ${canControl && isEnded ? `<button style="background:#7c3aed;color:#fff;border:none;padding:10px 14px;border-radius:9px;font-weight:600;cursor:pointer;" onclick="viewMeetingAttendance('${m._id}','${safeName}')">Attendance</button>` : ''}
        </div>
      </div>`;
    }

    const meetings = data.data || data.meetings || [];
    const live      = meetings.filter(m => m.status === 'live' || m.status === 'active');
    const scheduled = meetings.filter(m => m.status === 'scheduled');
    const past      = meetings.filter(m => ['ended', 'completed', 'cancelled'].includes(m.status));

    const lockBanner = isDeviceLocked ? `
      <div style="background:#fef3c7;border:1.5px solid #f59e0b;border-radius:10px;padding:12px 16px;margin-bottom:16px;font-size:13px;color:#92400e;">
        🔒 <strong>Device Lock Active</strong> — Joining meetings is blocked until ${new Date(devLock.lockedUntil).toLocaleTimeString(undefined,{hour:'2-digit',minute:'2-digit'})}. Contact your admin or HOD to unlock early.
      </div>` : '';

    function section(label, color, items) {
      if (!items.length) return '';
      return `<div style="font-size:11px;font-weight:700;letter-spacing:.8px;text-transform:uppercase;color:${color};margin-bottom:10px;">${label}</div>
              <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px;margin-bottom:24px;">${items.map(meetingCard).join('')}</div>`;
    }

    content.innerHTML = `
      <div class="page-header" style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;">
        <div><h2>Meetings</h2><p>Secure video meetings</p></div>
        ${canCreate ? `<div style="display:flex;gap:8px;">
          <button class="btn btn-primary btn-sm" onclick="showScheduleMeetingModal()" style="gap:6px;display:flex;align-items:center;">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
            Schedule
          </button>
          <button class="btn btn-success btn-sm" onclick="showInstantMeetingModal()" style="gap:6px;display:flex;align-items:center;">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polygon points="5 3 19 12 5 21 5 3"/></svg>
            Start Now
          </button>
        </div>` : ''}
      </div>
      ${lockBanner}
      ${meetings.length === 0 ? `<div class="card"><div class="empty-state"><p style="color:var(--text-muted);">No meetings scheduled yet.</p></div></div>` : ''}
      ${section('● Live Now', '#22c55e', live)}
      ${section('Scheduled', '#3b82f6', scheduled)}
      ${section('Past Meetings', '#94a3b8', past)}
    `;
  } catch (e) {
    content.innerHTML = `<div class="card"><p style="color:#ef4444;">Error: ${e.message}</p></div>`;
  }
}

function _meetingAudienceHTML(courseOptions) {
  const isCorp = currentUser?.company?.mode === 'corporate';
  return `
    <div class="form-group" style="margin-top:4px;">
      <label>Who can join?</label>
      <select id="meeting-audience" onchange="toggleMeetingCourseRow()" style="width:100%;padding:9px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:13px">
        <option value="everyone">Everyone in organisation</option>
        <option value="department">My department / team only</option>
        ${!isCorp ? '<option value="course">Specific course or group</option>' : ''}
      </select>
    </div>
    ${!isCorp ? `
    <div id="meeting-course-row" class="form-group" style="display:none;">
      <label>Course / Group *</label>
      <select id="meeting-course" style="width:100%;padding:9px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:13px">
        ${courseOptions}
      </select>
      <p style="font-size:11px;color:var(--text-muted);margin:4px 0 0;">Only students enrolled in this course (and group) will be able to join.</p>
    </div>` : ''}`;
}

function toggleMeetingCourseRow() {
  const audience = document.getElementById('meeting-audience')?.value;
  const row = document.getElementById('meeting-course-row');
  if (row) row.style.display = audience === 'course' ? '' : 'none';
}

function _resolveAudienceParams() {
  const audience = document.getElementById('meeting-audience')?.value || 'everyone';
  const courseId = document.getElementById('meeting-course')?.value  || '';
  const errEl    = document.getElementById('meeting-error');
  if (audience === 'course' && !courseId) {
    errEl.textContent = 'Please select a course or group.';
    errEl.style.display = 'block';
    return null;
  }
  if (audience === 'everyone')   return { openToCompany: true };
  if (audience === 'department') {
    const isCorp = currentUser?.company?.mode === 'corporate';
    return isCorp
      ? { openToCompany: false, allowedTeams: [currentUser?.team].filter(Boolean) }
      : { openToCompany: false, allowedDepartments: [currentUser?.department].filter(Boolean) };
  }
  if (audience === 'course')     return { openToCompany: false, linkedCourseId: courseId, allowedCourses: [courseId] };
  return { openToCompany: true };
}

async function _loadMeetingCourseOptions() {
  let courses = [];
  try {
    const d = await api('/api/courses');
    courses = d.courses || d || [];
  } catch(e) { courses = []; }
  return `<option value="">— Select a course / group —</option>` +
    courses.map(c => `<option value="${c._id}">${esc(c.title)}${c.level?' · L'+c.level:''}${c.group?' · Grp '+c.group:''}</option>`).join('');
}

