async function renderGradeBook() {
  const content = document.getElementById('main-content');
  if (!content) return;
  const isStudent = currentUser.role === 'student';
  if (isStudent) {
    await renderStudentGradeBook(content);
  } else {
    await renderLecturerGradeBook(content);
  }
}

